// Dedup against already-processed offenses, then map each NEW QRadar offense
// into an IRIS case body + SLA fields. Returns 0 items when nothing is new.
// Dedup against cases that already exist in IRIS (authoritative: the case's
// existence IS the dedup record, so it can never drift like a side file).
const casesResp = $('Get IRIS Cases').first().json;
const existing = Array.isArray(casesResp && casesResp.data) ? casesResp.data : ((casesResp && casesResp.data && casesResp.data.cases) || []);
const seen = new Set();
for (const c of existing) { const s = c && c.case_soc_id; if (typeof s === 'string' && s.indexOf('QR-') === 0) seen.add(s); }

const pad = n => String(n).padStart(2, '0');
const pretty = d => `${d.getUTCFullYear()}-${pad(d.getUTCMonth()+1)}-${pad(d.getUTCDate())} ${pad(d.getUTCHours())}:${pad(d.getUTCMinutes())}:${pad(d.getUTCSeconds())}`;

// QRadar offense_type id -> indicator semantics (common subset).
const OFFENSE_TYPE = {
  0: { label: 'Source IP', itype: 'ip' },
  1: { label: 'Destination IP', itype: 'ip' },
  2: { label: 'Event Name', itype: 'other' },
  3: { label: 'Username', itype: 'account' },
  4: { label: 'Source MAC', itype: 'mac' },
  5: { label: 'Destination MAC', itype: 'mac' },
  6: { label: 'Log Source', itype: 'other' },
  7: { label: 'Hostname', itype: 'hostname' },
};

// QRadar magnitude (1-10) -> severity string, SLA target hours, IRIS classification.
function sevFromMag(m) {
  if (m >= 9) return { sev: 'critical', hours: 4, classification: 3 };
  if (m >= 7) return { sev: 'high', hours: 8, classification: 2 };
  if (m >= 4) return { sev: 'medium', hours: 24, classification: 1 };
  return { sev: 'low', hours: 24, classification: 1 };
}

const now = new Date();
const out = [];

for (const item of $input.all()) {
  const o = item.json;
  if (!o || o.id == null) continue;
  const soc = `QR-${o.id}`;
  if (seen.has(soc)) continue; // a case already exists in IRIS for this offense

  const mag = Number(o.magnitude != null ? o.magnitude : (o.severity || 0));
  const { sev, hours, classification } = sevFromMag(mag);
  const ot = OFFENSE_TYPE[o.offense_type] || { label: `offense_type ${o.offense_type}`, itype: 'other' };
  const indicator = o.offense_source || 'unknown';
  const source_ip = ot.itype === 'ip' ? indicator : 'unknown';
  const status = o.status || 'OPEN';
  const assigned_to = o.assigned_to || 'unassigned';
  const descRaw = (o.description || '').trim();
  const cats = Array.isArray(o.categories) ? o.categories.join(', ') : '';
  const rules = Array.isArray(o.rules) ? o.rules.map(r => r.id).join(', ') : '';
  const logsrc = Array.isArray(o.log_sources) ? o.log_sources.map(l => l.name).join(', ') : '';
  const startTime = o.start_time ? new Date(o.start_time) : now;

  const opened_iso = now.toISOString();
  const opened_pretty = pretty(now);
  const due = new Date(now.getTime() + hours * 3600 * 1000);
  const due_iso = due.toISOString();
  const due_pretty = pretty(due);

  const descMd = [
    `# \uD83D\uDEA8 QRadar Offense ${o.id}: ${ot.label}`,
    ``,
    `${descRaw || '_No description provided._'}`,
    ``,
    `## \uD83D\uDCCC Detection details`,
    `| Field | Value |`,
    `| --- | --- |`,
    `| **Offense ID** | \`${o.id}\` |`,
    `| **Status** | ${status} |`,
    `| **Assigned to** | ${assigned_to} |`,
    `| **Magnitude** | ${o.magnitude} (sev ${o.severity} \u00B7 cred ${o.credibility} \u00B7 rel ${o.relevance}) |`,
    `| **Severity (SLA)** | \`${sev}\` |`,
    `| **Offense type** | ${ot.label} |`,
    `| **Source (offense_source)** | \`${indicator}\` |`,
    `| **Source network** | ${o.source_network || 'n/a'} |`,
    `| **Destination networks** | ${(o.destination_networks || []).join(', ') || 'n/a'} |`,
    `| **Categories** | ${cats || 'n/a'} |`,
    `| **Triggered rule IDs** | ${rules || 'n/a'} |`,
    `| **Log sources** | ${logsrc || 'n/a'} |`,
    `| **Events / Flows** | ${o.event_count} / ${o.flow_count} |`,
    `| **First seen** | ${pretty(startTime)} UTC |`,
    ``,
    `## \u23F1\uFE0F SLA / Case lifecycle`,
    `| Event | Timestamp |`,
    `| --- | --- |`,
    `| \uD83D\uDFE2 **Opened** | ${opened_pretty} UTC |`,
    `| \uD83D\uDD34 **Closed** | _pending \u2014 written on close_ |`,
    ``,
    `| SLA metric | Value |`,
    `| --- | --- |`,
    `| **Target (${sev})** | ${hours}h |`,
    `| **Due by** | ${due_pretty} UTC |`,
    `| **Time to resolve** | _pending_ |`,
    `| **Status** | \u23F3 Open |`,
    ``,
    `---`,
    `*Polled from QRadar \u00B7 threat-intel enrichment is posted as a note.*`,
  ].join('\n');

  const caseBody = {
    case_name: `[QR-${o.id}] ${ot.label} from ${indicator}`,
    case_description: descMd,
    case_soc_id: soc,
    case_customer: 1,
    case_classification: classification,
    case_tags: `opened ${pad((now.getUTCHours()+4)%24)}:${pad(now.getUTCMinutes())} AZT`,
  };

  out.push({ json: {
    offense_id: o.id,
    severity: sev,
    target_hours: hours,
    opened_iso, opened_pretty, due_iso, due_pretty,
    classification,
    indicator, indicator_type: ot.itype, source_ip,
    status, assigned_to,
    caseBody,
  } });
}

return out;

// Mark each offense as processed (seen file) and log an sla_started event so the
// existing SLA poller can complete the SLA block when the case is closed in IRIS.
const fs = require('fs');
const WS_DIR = '/home/node/.n8n/workspace';
try { fs.mkdirSync(WS_DIR, { recursive: true }); } catch (e) {}
const logPath = WS_DIR + '/siem-sla-metrics.jsonl';

const built = $('Build QRadar Case').all();
const results = [];

$input.all().forEach((item, i) => {
  const j = item.json;
  const idx = (item.pairedItem && typeof item.pairedItem.item === 'number') ? item.pairedItem.item : i;
  const bcf = (built[idx] && built[idx].json) || (built[0] && built[0].json) || {};
  const irisCaseId = (j && j.data && (j.data.case_id || j.data.id)) || (j && j.case_id);

  try {
    fs.appendFileSync(logPath, JSON.stringify({
      case_id: irisCaseId, offense_id: bcf.offense_id, sla_start: bcf.opened_iso,
      severity: bcf.severity, target_hours: bcf.target_hours, due: bcf.due_iso,
      event: 'sla_started', src: 'qradar',
    }) + '\n');
  } catch (e) { j.sla_file_error = e.message; }

  results.push({ json: {
    iris_case_id: irisCaseId,
    offense_id: bcf.offense_id,
    severity: bcf.severity,
    sla_start: bcf.opened_iso,
    target_hours: bcf.target_hours,
    due_iso: bcf.due_iso,
    sla_status: 'running',
    indicator: bcf.indicator,
    indicator_type: bcf.indicator_type,
    source_ip: bcf.source_ip,
  } });
});

return results;

// One item per new case that has an enrichable IP indicator (skip unknown / non-IP).
return $input.all()
  .filter(item => item.json.iris_case_id
    && item.json.indicator_type === 'ip'
    && item.json.indicator
    && item.json.indicator !== 'unknown')
  .map(item => ({ json: {
    case_id: item.json.iris_case_id,
    indicator: item.json.indicator,
    indicator_type: item.json.indicator_type,
    source_ip: item.json.source_ip,
  } }));

// Capture offenses whose IRIS case creation failed. They are NOT written to the
// seen-file (Store SLA Start only runs on success), so they retry on the next poll.
const fs = require('fs');
const WS_DIR = '/home/node/.n8n/workspace';
try { fs.mkdirSync(WS_DIR, { recursive: true }); } catch (e) {}
const ERR = '/home/node/.n8n/workspace/qradar-errors.jsonl';
const built = $('Build QRadar Case').all();
const out = [];

$input.all().forEach((item, i) => {
  const j = item.json || {};
  const idx = (item.pairedItem && typeof item.pairedItem.item === 'number') ? item.pairedItem.item : i;
  const bcf = (built[idx] && built[idx].json) || {};
  let errMsg = j.error || (j.error && j.error.message) || j.message || 'unknown error';
  if (typeof errMsg !== 'string') errMsg = JSON.stringify(errMsg);

  try {
    fs.appendFileSync(ERR, JSON.stringify({
      offense_id: bcf.offense_id, severity: bcf.severity, error: errMsg,
      at: new Date().toISOString(), event: 'iris_create_failed',
    }) + '\n');
  } catch (e) {}

  out.push({ json: { offense_id: bcf.offense_id, failed: true, error: errMsg } });
});

return out;
